class User_Model_UserUtmParams extends User_Model_Base_UserUtmParams {

    /**
     * @throws Exception
     */
    public static function insertUtmParams(array $utmParamsArray): int {
        $utmParams = str_replace('utm_', '', $utmParamsArray);
        $userUtm = new self();
        $userUtm->DateTime = date('Y-m-d H:i:s');
        foreach( $utmParams as $utmParam) {
            $utmValue = explode('=',$utmParam);
            $userUtm[ucfirst($utmValue[0])] = $utmValue[1];
        }
        $userUtm->save();
        return $userUtm->ID;
    }
}